=Analyse this customer support screenshot.

Image/Video URL: {{ $json.cdnUrl }}
Product Area: {{ $json.productArea }}
Customer Description: {{ $json.userDescription || 'No description provided' }}
Platform: {{ $json.platform }}
Ticket ID: {{ $json.ticketId }}

Return ONLY this JSON:
{
  "errorSummary": "One-sentence plain English summary of what the customer is experiencing",
  "visibleErrorMessage": "Exact error text visible in the screenshot, or null if none",
  "errorCode": "HTTP status code or app error code if visible, or null",
  "affectedComponent": "Specific UI component, page, or feature affected",
  "affectedUrl": "URL visible in browser address bar if present, or null",
  "browserOrOS": "Browser name/version or OS if identifiable from screenshot, or null",
  "reproducibilityHint": "What state the UI appears to be in that might help reproduce the bug",
  "developerNotes": "Technical observations: console errors visible, network state, loading indicators, broken elements",
  "suggestedPriority": "critical|high|medium|low",
  "detectedKeywords": ["array", "of", "technical", "keywords", "found"],
  "suggestedLabels": ["frontend", "checkout", "etc"],
  "isScreenRecording": false,
  "confidenceScore": 0.92
}

